func TestEnumDataExportStatus(t *testing.T) {
	t.Run("NewFromString_failure", func(t *testing.T) {
		t.Parallel()
		val, err := NewDataExportStatusFromString("failure")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, DataExportStatus("failure"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_pending", func(t *testing.T) {
		t.Parallel()
		val, err := NewDataExportStatusFromString("pending")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, DataExportStatus("pending"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_success", func(t *testing.T) {
		t.Parallel()
		val, err := NewDataExportStatusFromString("success")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, DataExportStatus("success"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewDataExportStatusFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewDataExportStatusFromString("failure")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

